class Solution {
public:
    int minMoves(vector<int>& nums) {
        long long s=0; int mn=INT_MAX;
        for(int x:nums){ s+=x; mn=min(mn,x); }
        return (int)(s - 1LL*nums.size()*mn);
    }
};

