int minMoves(int* nums, int n) {
    long long s=0; int mn=INT_MAX;
    for(int i=0;i<n;i++){ s+=nums[i]; if(nums[i]<mn) mn=nums[i]; }
    return (int)(s - (long long)n*mn);
}
